import{_ as s,a,b as t}from"./chunks/resolve_fusion_page.CmQGpMse.js";import{_ as i,o as p,c as r,a2 as l}from"./chunks/framework.CkaEw-3u.js";const y=JSON.parse('{"title":"使い方","description":"","frontmatter":{"title":"使い方","head":[["link",{"rel":"canonical","href":"https://mug-lab-3.github.io/mug-typography-docs/guide/getting-started.html"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:site_name","content":"Mug Typography Manual"}],["meta",{"property":"og:locale","content":"ja_JP"}],["meta",{"property":"og:title","content":"使い方 | Mug Typography Manual"}],["meta",{"property":"og:description","content":"文字をパーツまで分解して動かせる、DaVinci Resolve対応OFXプラグイン Mug Typography のオンラインマニュアル"}],["meta",{"property":"og:url","content":"https://mug-lab-3.github.io/mug-typography-docs/guide/getting-started.html"}],["meta",{"property":"og:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"property":"og:image:type","content":"image/jpeg"}],["meta",{"property":"og:image:width","content":"1200"}],["meta",{"property":"og:image:height","content":"630"}],["meta",{"property":"og:image:alt","content":"Mug Typography Online Manual"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:site","content":"@MugLab3"}],["meta",{"name":"twitter:title","content":"使い方 | Mug Typography Manual"}],["meta",{"name":"twitter:description","content":"文字をパーツまで分解して動かせる、DaVinci Resolve対応OFXプラグイン Mug Typography のオンラインマニュアル"}],["meta",{"name":"twitter:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"name":"twitter:image:alt","content":"Mug Typography Online Manual"}]]},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),n={name:"guide/getting-started.md"};function c(o,e,d,g,m,h){return p(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="使い方" tabindex="-1">使い方 <a class="header-anchor" href="#使い方" aria-label="Permalink to &quot;使い方&quot;">​</a></h1><p>本プラグインには、2D用の6プリセットと3D用の2プリセットがあります。まず平面的なタイポグラフィか、カメラと奥行きを使う3D表現かを選び、次にパーツ編集の有無とテキスト量に合わせてプリセットを決めます。</p><p><small class="trial-note">Trial版では、選択したプリセットに関わらず最大文字数が一律 8文字に制限されます。</small></p><h3 id="step-1-2dか3dかを選ぶ" tabindex="-1">STEP 1: 2Dか3Dかを選ぶ <a class="header-anchor" href="#step-1-2dか3dかを選ぶ" aria-label="Permalink to &quot;STEP 1: 2Dか3Dかを選ぶ&quot;">​</a></h3><div class="preset-grid preset-grid-2"><div class="preset-card preset-recommended"><span class="preset-badge">基本</span><p class="preset-name">Mug Typography <span class="preset-variant">2D</span></p><p class="preset-tagline">通常のタイトル・字幕・モーションに</p><p class="preset-desc">位置、回転、スケール、ストレッチを中心に、文字とパーツを平面上で編集します。Low / Mid / Highから処理上限を選べます。</p></div><div class="preset-card"><p class="preset-name">Mug Typography <span class="preset-variant">3D</span></p><p class="preset-tagline">カメラ・遠近感・奥行きを使う表現に</p><p class="preset-desc">Camera Settingsと3D変形を搭載。文字やパーツをZ方向へ配置できます。上限はMid相当です。詳しくは「<a href="../features/feature-3d.html">3Dタイポグラフィを作る</a>」を参照してください。</p></div></div><h3 id="step-2-通常版か-lite-版かを選ぶ" tabindex="-1">STEP 2: 通常版か Lite 版かを選ぶ <a class="header-anchor" href="#step-2-通常版か-lite-版かを選ぶ" aria-label="Permalink to &quot;STEP 2: 通常版か Lite 版かを選ぶ&quot;">​</a></h3><div class="preset-grid preset-grid-2"><div class="preset-card"><p class="preset-name">Mug Typography <span class="preset-variant">通常版</span></p><p class="preset-tagline">パーツ単位で細かく制御したい方に</p><p class="preset-desc">Part Settings（パーツ個別調整）を搭載。文字を構成するパーツ一つひとつにパラメータを設定できます。</p></div><div class="preset-card"><p class="preset-name">Mug Typography <span class="preset-variant">Lite 版</span></p><p class="preset-tagline">パーツ単位の編集が不要な方に</p><p class="preset-desc">Part Settings を省略し、ロードと処理が高速。最大文字数は通常版の <strong>1.5倍</strong>、パーツ数は描画上限の <strong>512</strong> まで扱えます。</p></div></div><h3 id="step-3-2dではサイズ-low-mid-high-を選ぶ" tabindex="-1">STEP 3: 2Dではサイズ（Low / Mid / High）を選ぶ <a class="header-anchor" href="#step-3-2dではサイズ-low-mid-high-を選ぶ" aria-label="Permalink to &quot;STEP 3: 2Dではサイズ（Low / Mid / High）を選ぶ&quot;">​</a></h3><p>3D版はMid相当の上限に固定されています。2D版を選んだ場合は、入力するテキストの長さや文字の複雑さに合わせてサイズを選びます。</p><div class="preset-grid"><div class="preset-card"><p class="preset-name">サイズ <span class="preset-variant">Low</span></p><p class="preset-tagline">短いテキストに</p><div class="preset-limits"><div class="preset-limit"><span class="limit-value">16</span><span class="limit-sub">Lite: 24</span><span class="limit-label">最大文字数</span></div><div class="preset-limit"><span class="limit-value">60</span><span class="limit-sub">Lite: 512</span><span class="limit-label">最大パーツ数</span></div></div><p class="preset-note">動作が最も軽快です</p></div><div class="preset-card preset-recommended"><span class="preset-badge">推奨</span><p class="preset-name">サイズ <span class="preset-variant">Mid</span></p><p class="preset-tagline">通常のテキストに</p><div class="preset-limits"><div class="preset-limit"><span class="limit-value">30</span><span class="limit-sub">Lite: 45</span><span class="limit-label">最大文字数</span></div><div class="preset-limit"><span class="limit-value">84</span><span class="limit-sub">Lite: 512</span><span class="limit-label">最大パーツ数</span></div></div><p class="preset-note">迷ったらまずこちらを選択</p></div><div class="preset-card"><p class="preset-name">サイズ <span class="preset-variant">High</span></p><p class="preset-tagline">長文・複雑な漢字に</p><div class="preset-limits"><div class="preset-limit"><span class="limit-value">60</span><span class="limit-sub">Lite: 90</span><span class="limit-label">最大文字数</span></div><div class="preset-limit"><span class="limit-value">170</span><span class="limit-sub">Lite: 512</span><span class="limit-label">最大パーツ数</span></div></div><p class="preset-note">⚠️ メモリ消費が大きめです</p></div></div><p>2Dの6種類と3Dの2種類を合わせ、使用できるプリセットは計8種類です。</p><p><img src="'+s+'" alt="DaVinci Resolve のエフェクトライブラリに表示される8プリセットの一覧"></p><p><em>DaVinci Resolve のエフェクトライブラリでの表示</em></p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>パラメーター数が多いプリセットほど、クリップやノードを切り替えた際のレスポンスが低下します。必要な文字数・パーツ数を考慮して、適切なプリセットを選択してください。 各プリセットの上限値は、<code>preferences.json</code> の <code>maxCharacters</code> / <code>maxParts</code> で変更することもできます（調整方法は付録の「<a href="/mug-typography-docs/reference/appendix.html#環境設定のカスタマイズ-preferences-json">環境設定のカスタマイズ (preferences.json)</a>」を参照）。</p></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>各上限を超えた場合、超えた分は<strong>描画されません</strong>。</p><ul><li><strong>最大文字数</strong>を超えた場合: 先頭から数えて上限を超えた文字以降が描画されません。</li><li><strong>最大パーツ数</strong>の上限に達した場合: 上限に達した時点の文字以降が、文字単位でまとめて描画されなくなります（1文字の一部だけが欠けることはありません）。</li></ul><p>現在有効な上限値は、Inspector 最上部の <strong>Version</strong> 欄に <code>(C: 文字数, P: パーツ数)</code> の形式で常時表示されています。テキストが表示されない場合は、まずここを確認してください。</p></div><h2 id="edit-ページ" tabindex="-1">Edit ページ <a class="header-anchor" href="#edit-ページ" aria-label="Permalink to &quot;Edit ページ&quot;">​</a></h2><p>エフェクトライブラリの <strong>Open FX</strong> には、用途に合わせて以下の2つの場所に上記の8プリセットが用意されています。タイムラインに配置またはクリップへ適用してご使用ください。</p><div class="preset-grid preset-grid-2"><div class="preset-card"><p class="preset-variant">Generator</p><ul class="preset-tree"><li class="tree-root">Effect Library</li><li class="tree-depth-1">Open FX</li><li class="tree-depth-2 tree-branch">Generators</li><li class="tree-depth-3">MugLab</li><li class="tree-depth-4 tree-leaf">Mug Typography (Low / Mid / High / Lite / 3D…) 全8種</li></ul><p class="preset-tagline">新規クリップとして配置</p><p class="preset-desc">タイムライン上に新規クリップとして直接配置したい場合に使用します。ドラッグ＆ドロップでタイムライン上に配置できます。</p></div><div class="preset-card"><p class="preset-variant">Filter</p><ul class="preset-tree"><li class="tree-root">Effect Library</li><li class="tree-depth-1">Open FX</li><li class="tree-depth-2 tree-branch">Filters</li><li class="tree-depth-3">MugLab</li><li class="tree-depth-4 tree-leaf">Mug Typography (Low / Mid / High / Lite / 3D…) 全8種</li></ul><p class="preset-tagline">既存クリップへのエフェクトとして適用</p><p class="preset-desc">既存のクリップに対して、エフェクトとして本プラグインを適用したい場合に使用します。<strong>Color ページ</strong>などの他のページではこちら（Filters）のみが表示されます。</p></div></div><h3 id="ビューア上での操作を有効にする" tabindex="-1">ビューア上での操作を有効にする <a class="header-anchor" href="#ビューア上での操作を有効にする" aria-label="Permalink to &quot;ビューア上での操作を有効にする&quot;">​</a></h3><p>プレビュー画面上でのハンドル操作（移動・回転・スケールなど）を使うには、タイムライン左下の四角く囲った部分をクリック → <strong>Open FX Overlay</strong> に設定してください。</p><p><img src="'+a+'" alt="Edit ページでの使用例"></p><p><em>Edit ページでの使用例（左下の切り替えで Open FX Overlay を選択）</em></p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Edit ページには DaVinci Resolve の仕様による制限があります。詳細は付録の「<a href="/mug-typography-docs/reference/appendix.html#制限事項">制限事項</a>」を参照してください。</p></div><h2 id="fusion-ページ" tabindex="-1">Fusion ページ <a class="header-anchor" href="#fusion-ページ" aria-label="Permalink to &quot;Fusion ページ&quot;">​</a></h2><p>Fusion ページでは、以下の場所から必要なプリセットのノードをノードグラフに追加して使用します。 Edit ページと同じ8種類のプリセットが、すべてノードとして追加できます。</p><ul class="preset-tree"><li class="tree-root">Tools</li><li class="tree-depth-1">OpenFX</li><li class="tree-depth-2">MugLab</li><li class="tree-depth-3 tree-leaf">Mug Typography (Low / Mid / High / Lite / 3D…) 全8種</li></ul><p>ノードの <strong>Input</strong> 端子は、接続しなくても単体で使用できます。接続した場合は、入力画像が背景として描画され、その上にテキストが合成されます。</p><p><img src="'+t+'" alt="Fusion ページでの使用例"></p><p><em>Fusion ページでの使用例（Mug Typography ノードを追加）</em></p><hr><p><a id="basic-concepts-ja"></a></p>',31)])])}const b=i(n,[["render",c]]);export{y as __pageData,b as default};
